tests:
def test_basic_call():
    m = Mock(return_value=42)
    assert m() == 42

def test_side_effect_exception_class():
    m = Mock(side_effect=ValueError)
    try:
        m()
        assert False
    except ValueError:
        pass

def test_side_effect_exception_instance():
    m = Mock(side_effect=RuntimeError('boom'))
    try:
        m()
        assert False
    except RuntimeError as e:
        assert str(e) == 'boom'

def test_side_effect_callable():
    m = Mock(side_effect=lambda x: x * 2)
    assert m(5) == 10
